    ()
  }

  def uploadFile(bucketName: String, key: String, filePath: String): Try[Unit] = Try {
    val putObjectRequest = PutObjectRequest.builder()
      .bucket(bucketName)
      .key(key)
      .build()
    
    s3Client.putObject(putObjectRequest, RequestBody.fromFile(Paths.get(filePath)))
    ()
  }

  def downloadFile(bucketName: String, key: String, destinationPath: String): Try[Unit] = Try {
    val getObjectRequest = GetObjectRequest.builder()
      .bucket(bucketName)
      .key(key)
      .build()
    
    val responseBytes = s3Client.getObjectAsBytes(getObjectRequest)
    Files.write(Paths.get(destinationPath), responseBytes.asByteArray())
    ()
  }

  def deleteObject(bucketName: String, key: String): Try[Unit] = Try {
    val deleteObjectRequest = DeleteObjectRequest.builder()
      .bucket(bucketName)
      .key(key)
      .build()
    
    s3Client.deleteObject(deleteObjectRequest)
    ()
  }

  def listObjects(bucketName: String, prefix: Option[String] = None): Try[List[String]] = Try {
    val requestBuilder = ListObjectsV2Request.builder()
      .bucket(bucketName)
    
    val request = prefix match {
      case Some(p) => requestBuilder.prefix(p).build()
      case None => requestBuilder.build()
    }
    
    s3Client.listObjectsV2(request).contents().asScala.map(_.key()).toList
  }

  def close(): Unit = {
    s3Client.close()
  }
}

